+  it("accepts multibyte callback_data at 64 bytes and rejects 68 bytes", () => {
+    expect(
+      readTelegramButtons({
+        buttons: [[{ text: "Option A", callback_data: "😀".repeat(16) }]],
+      }),
+    ).toEqual([[{ text: "Option A", callback_data: "😀".repeat(16) }]]);
+
